/**
 * Restore every plan day in the given week back to its seeded prescription. Days that have never been edited are left alone. Logged workouts are not touched.
 */
export const ResetPlanWeekParams = zod.object({
  week: zod.coerce.number(),
});

export const ResetPlanWeekResponse = zod.object({
  week: zod.number(),
  daysReset: zod
    .number()
    .describe(
      "Number of plan days that actually had a seed snapshot to restore from. Untouched days are not counted.",
    ),
  daysTotal: zod
    .number()
    .describe(
      "Total number of plan days in the week (including untouched ones).",
    ),
  undoToken: zod
    .string()
    .nullish()
    .describe(
      "Short-lived token that can be passed to POST \/plan\/reset\/undo to restore the just-wiped customizations. Null when nothing was reset (i.e. daysReset is 0). Expires after roughly 30 seconds.",
    ),
  undoExpiresInSeconds: zod
    .number()
    .nullish()
    .describe(
      "Approximate number of seconds the undoToken will remain valid for. Null when undoToken is null.",
    ),
});

/**
 * Restore every plan day in the entire 52-week plan back to its seeded prescription. Days that have never been edited are left alone. Logged workouts are not touched.
 */
export const ResetPlanResponse = zod.object({
  weeksReset: zod
    .number()
    .describe(
      "Number of weeks that contained at least one previously-edited plan day.",
    ),
  daysReset: zod
    .number()
    .describe(
      "Number of plan days that actually had a seed snapshot to restore from. Untouched days are not counted.",
    ),
  daysTotal: zod
    .number()
    .describe(
      "Total number of plan days across the entire plan (including untouched ones).",
    ),
  undoToken: zod
    .string()
    .nullish()
    .describe(
      "Short-lived token that can be passed to POST \/plan\/reset\/undo to restore the just-wiped customizations. Null when nothing was reset (i.e. daysReset is 0). Expires after roughly 30 seconds.",
    ),
  undoExpiresInSeconds: zod
    .number()
    .nullish()
    .describe(
      "Approximate number of seconds the undoToken will remain valid for. Null when undoToken is null.",
    ),
});

/**
 * Nuclear reset. TRUNCATEs and reseeds plan_weeks and plan_days from the
canonical generator (clearing every customization), and wipes every
logged workout, every body measurement (re-inserting only the seeded
baseline row), the race-week checklist, and any pending reset-undo
snapshots. There is no undo for this operation. Use only when the user
wants to start the campaign over from day one.

 */
export const FullResetPlanResponse = zod.object({
  weeksSeeded: zod
    .number()
    .describe(
      "Number of plan_weeks rows reinserted from the canonical generator (52 for the standard campaign).",
    ),
  daysSeeded: zod
    .number()
    .describe(
      "Number of plan_days rows reinserted from the canonical generator (364 for the standard campaign).",
    ),
  workoutsWiped: zod
    .number()
    .describe("Number of logged workout rows that were deleted by the reset."),
  measurementsWiped: zod
    .number()
    .describe(
      "Number of measurements rows that were deleted by the reset (includes the baseline row, which is then reinserted from the seed).",
    ),
  measurementsSeeded: zod
    .number()
    .describe(
      "Number of baseline measurements rows reinserted from the seed (1 for the standard campaign).",
    ),
  checklistItemsWiped: zod
    .number()
    .describe(
      "Number of race-week checklist rows that were deleted by the reset.",
    ),
  undoSnapshotsWiped: zod
    .number()
    .describe(
      "Number of pending reset-undo snapshots that were dropped (so a stale Undo can't restore deleted state after the full reset).",
    ),
});

/**
 * Restore the plan days that were just wiped by the most recent week-reset or plan-reset call. The undo token is only valid for a short window (~30 seconds) after the reset; after that the snapshot is dropped and the call returns 404.
 */
export const UndoPlanResetBody = zod.object({
  undoToken: zod
    .string()
    .describe(
      "Token previously returned by POST \/plan\/weeks\/{week}\/reset or POST \/plan\/reset.",
    ),
});

export const UndoPlanResetResponse = zod.object({
  daysRestored: zod
    .number()
    .describe(
      "Number of plan days whose pre-reset customizations were restored.",
    ),
  weeksAffected: zod
    .array(zod.number())
    .describe(
      "Plan-week numbers whose aggregates were recomputed by the undo.",
    ),
});

